package kotlinx.coroutines

import kotlin.test.*
import kotlin.time.*

class DelayRoundingTest : TestBase() {

    @Test
    fun testToDelayMillisRoundsUp() {
        // Test that sub-millisecond components cause rounding up
        val duration1 = 998.milliseconds + 902752.nanoseconds
        val millis1 = duration1.toDelayMillis()
        // Should round up to 999ms since there's a nanosecond component
        assertEquals(999L, millis1)

        val duration2 = 1.milliseconds + 1.nanoseconds
        val millis2 = duration2.toDelayMillis()
        // Should round up to 2ms
        assertEquals(2L, millis2)

        val duration3 = 100.milliseconds + 500000.nanoseconds
        val millis3 = duration3.toDelayMillis()
        // Should round up to 101ms
        assertEquals(101L, millis3)

        // Exact millisecond values should not round up
        val duration4 = 100.milliseconds
        val millis4 = duration4.toDelayMillis()
        assertEquals(100L, millis4)

        // Microsecond durations should round up
        val duration5 = 500.microseconds
        val millis5 = duration5.toDelayMillis()
        // 500 microseconds = 0.5ms, should round up to 1ms
        assertEquals(1L, millis5)

        // Small nanosecond durations should round up to 1ms
        val duration6 = 1.nanoseconds
        val millis6 = duration6.toDelayMillis()
        assertEquals(1L, millis6)
    }

    @Test
    fun testToDelayMillisEdgeCases() {
        // Zero duration
        assertEquals(0L, Duration.ZERO.toDelayMillis())

        // Negative duration
        assertEquals(0L, (-1).milliseconds.toDelayMillis())
        assertEquals(0L, (-1).nanoseconds.toDelayMillis())

        // Duration exactly at millisecond boundary
        val exactMillisecond = 250.milliseconds
        assertEquals(250L, exactMillisecond.toDelayMillis())
    }

    @Test
    fun testDelayWithSubMillisecondPrecision() = runTest {
        val expectedDuration = 998.milliseconds + 902752.nanoseconds
        val actualDuration = measureTime {
            delay(expectedDuration)
        }
        // The actual duration should be at least the expected duration
        // (since we rounded up to ensure the delay is at least as long as requested)
        val difference = actualDuration - expectedDuration
        assertTrue(difference.isPositive(), "Actual duration $actualDuration should be at least expected duration $expectedDuration")
    }

    @Test
    fun testDelayWithMicrosecondPrecision() = runTest {
        val expectedDuration = 500.microseconds
        val actualDuration = measureTime {
            delay(expectedDuration)
        }
        // The actual duration should be at least the expected duration
        val difference = actualDuration - expectedDuration
        assertTrue(difference.isPositive(), "Actual duration $actualDuration should be at least expected duration $expectedDuration")
    }

    @Test
    fun testDelayWithExactMillisecond() = runTest {
        val expectedDuration = 100.milliseconds
        val actualDuration = measureTime {
            delay(expectedDuration)
        }
        // The actual duration should be at least the expected duration
        val difference = actualDuration - expectedDuration
        assertTrue(difference.isPositive(), "Actual duration $actualDuration should be at least expected duration $expectedDuration")
    }
}"}

